 if(Number.isFinite(rules.gustKt)&&maxGust>=Number(rules.gustKt))alerts.push(`Böen bis ${Math.round(maxGust)} kt`);
 if(Number.isFinite(rules.frostC)&&minTemp<=Number(rules.frostC))alerts.push(`Temperatur bis ${Math.round(minTemp)} °C`);
