 snowGrains:{label:'Schneegriesel',legendClass:'snow-grains',fill:'url(#snowGrainsPattern)'},
 snowShowers:{label:'Schneeschauer',legendClass:'snow-showers',fill:'url(#snowShowersPattern)'},
